using MaintenanceCMMS.Infrastructure.Data.PostgreSql.Entities;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace MaintenanceCMMS.Infrastructure.Data.PostgreSql.Configurations;

public sealed class MaterialRequestConfiguration : IEntityTypeConfiguration<MaterialRequestEntity>
{
    public void Configure(EntityTypeBuilder<MaterialRequestEntity> b)
    {
        b.ToTable("solicitudes_repuestos"); b.ConfigureBase();
        b.Property(x => x.RequestNumber).HasColumnName("numero_solicitud").HasMaxLength(80).IsRequired(); b.Property(x => x.Status).HasColumnName("estado").HasMaxLength(80).IsRequired(); b.Property(x => x.RequestType).HasColumnName("tipo").HasMaxLength(80).IsRequired(); b.Property(x => x.Source).HasColumnName("origen").HasMaxLength(80).IsRequired(); b.Property(x => x.FaenaId).HasColumnName("faena_id"); b.Property(x => x.WorkOrderId).HasColumnName("orden_trabajo_id"); b.Property(x => x.AssetId).HasColumnName("activo_id"); b.Property(x => x.WarehouseId).HasColumnName("bodega_id"); b.Property(x => x.RequesterUserId).HasColumnName("solicitante_usuario_id").HasMaxLength(120).IsRequired(); b.Property(x => x.RequestedAtUtc).HasColumnName("solicitado_at_utc").HasColumnType("timestamptz"); b.Property(x => x.TechnicalDescription).HasColumnName("descripcion_tecnica").HasMaxLength(1000).IsRequired(); b.Property(x => x.Unit).HasColumnName("unidad").HasMaxLength(40).IsRequired(); b.Property(x => x.Reason).HasColumnName("motivo").HasMaxLength(500).IsRequired(); b.Property(x => x.PhotoReference).HasColumnName("foto_referencia").HasMaxLength(1000); b.Property(x => x.TaskCode).HasColumnName("codigo_tarea").HasMaxLength(80); b.Property(x => x.StockDecision).HasColumnName("decision_stock").HasMaxLength(500); b.Property(x => x.MaintenanceApproverUserId).HasColumnName("aprobador_mantenimiento_usuario_id").HasMaxLength(120); b.Property(x => x.MaintenanceApprovedAtUtc).HasColumnName("aprobado_mantenimiento_at_utc").HasColumnType("timestamptz"); b.Property(x => x.WarehouseApproverUserId).HasColumnName("aprobador_bodega_usuario_id").HasMaxLength(120); b.Property(x => x.WarehouseApprovedAtUtc).HasColumnName("aprobado_bodega_at_utc").HasColumnType("timestamptz"); b.Property(x => x.RejectedByUserId).HasColumnName("rechazado_por_usuario_id").HasMaxLength(120); b.Property(x => x.RejectedAtUtc).HasColumnName("rechazado_at_utc").HasColumnType("timestamptz"); b.Property(x => x.RejectReason).HasColumnName("motivo_rechazo").HasMaxLength(500); b.Property(x => x.ReceivedByUserId).HasColumnName("recibido_por_usuario_id").HasMaxLength(120); b.Property(x => x.ReceivedAtUtc).HasColumnName("recibido_at_utc").HasColumnType("timestamptz"); b.Property(x => x.ConvertedByUserId).HasColumnName("convertido_por_usuario_id").HasMaxLength(120); b.Property(x => x.ConvertedAtUtc).HasColumnName("convertido_at_utc").HasColumnType("timestamptz"); b.Property(x => x.ClosedAtUtc).HasColumnName("cerrado_at_utc").HasColumnType("timestamptz"); b.Property(x => x.Observations).HasColumnName("observaciones").HasMaxLength(2000);
        b.HasIndex(x => x.RequestNumber).IsUnique(); b.HasIndex(x => new { x.FaenaId, x.Status }); b.HasOne(x => x.Faena).WithMany().HasForeignKey(x => x.FaenaId).OnDelete(DeleteBehavior.Restrict); b.HasOne(x => x.WorkOrder).WithMany().HasForeignKey(x => x.WorkOrderId).OnDelete(DeleteBehavior.Restrict); b.HasOne(x => x.Asset).WithMany().HasForeignKey(x => x.AssetId).OnDelete(DeleteBehavior.Restrict); b.HasOne(x => x.Warehouse).WithMany().HasForeignKey(x => x.WarehouseId).OnDelete(DeleteBehavior.Restrict);
    }
}

public sealed class MaterialRequestItemConfiguration : IEntityTypeConfiguration<MaterialRequestItemEntity>
{
    public void Configure(EntityTypeBuilder<MaterialRequestItemEntity> b)
    {
        b.ToTable("solicitud_repuesto_items"); b.ConfigureBase(); b.Property(x => x.MaterialRequestId).HasColumnName("solicitud_repuesto_id"); b.Property(x => x.SparePartId).HasColumnName("repuesto_id"); b.Property(x => x.ReservationId).HasColumnName("reserva_id"); b.Property(x => x.MasterSparePartCode).HasColumnName("repuesto_maestro_codigo").HasMaxLength(80); b.Property(x => x.RequestedQuantity).HasColumnName("cantidad_solicitada").HasColumnType("numeric(14,2)"); b.Property(x => x.ApprovedQuantity).HasColumnName("cantidad_aprobada").HasColumnType("numeric(14,2)"); b.Property(x => x.ReservedQuantity).HasColumnName("cantidad_reservada").HasColumnType("numeric(14,2)"); b.Property(x => x.DeliveredQuantity).HasColumnName("cantidad_entregada").HasColumnType("numeric(14,2)"); b.Property(x => x.ReturnedQuantity).HasColumnName("cantidad_devuelta").HasColumnType("numeric(14,2)"); b.Property(x => x.Unit).HasColumnName("unidad").HasMaxLength(40).IsRequired(); b.Property(x => x.DeliveryMovementNumber).HasColumnName("movimiento_entrega_numero").HasMaxLength(80); b.Property(x => x.Observations).HasColumnName("observaciones").HasMaxLength(1000); b.HasOne(x => x.MaterialRequest).WithMany(x => x.Items).HasForeignKey(x => x.MaterialRequestId).OnDelete(DeleteBehavior.Restrict); b.HasOne(x => x.SparePart).WithMany().HasForeignKey(x => x.SparePartId).OnDelete(DeleteBehavior.Restrict); b.HasOne(x => x.Reservation).WithMany().HasForeignKey(x => x.ReservationId).OnDelete(DeleteBehavior.Restrict); b.ToTable(t => t.HasCheckConstraint("ck_solicitud_repuesto_items_cantidades", "cantidad_solicitada > 0 AND cantidad_aprobada >= 0 AND cantidad_reservada >= 0 AND cantidad_entregada >= 0 AND cantidad_devuelta >= 0"));
    }
}

public sealed class MaterialRequestStatusHistoryConfiguration : IEntityTypeConfiguration<MaterialRequestStatusHistoryEntity>
{
    public void Configure(EntityTypeBuilder<MaterialRequestStatusHistoryEntity> b)
    {
        b.ToTable("solicitud_repuesto_historial"); b.ConfigureBase(); b.Property(x => x.MaterialRequestId).HasColumnName("solicitud_repuesto_id"); b.Property(x => x.PreviousStatus).HasColumnName("estado_anterior").HasMaxLength(80).IsRequired(); b.Property(x => x.NewStatus).HasColumnName("estado_nuevo").HasMaxLength(80).IsRequired(); b.Property(x => x.UserId).HasColumnName("usuario_id").HasMaxLength(120).IsRequired(); b.Property(x => x.OccurredAtUtc).HasColumnName("fecha_utc").HasColumnType("timestamptz"); b.Property(x => x.Reason).HasColumnName("motivo").HasMaxLength(500).IsRequired(); b.HasOne(x => x.MaterialRequest).WithMany(x => x.History).HasForeignKey(x => x.MaterialRequestId).OnDelete(DeleteBehavior.Restrict); b.HasIndex(x => new { x.MaterialRequestId, x.OccurredAtUtc });
    }
}
